func configurarBusca(repositorio: ItemRepositorio) {
    let textoPub = publisher(for: \.textoBusca)
        .debounce(for: .milliseconds(300), scheduler: RunLoop.main)
        .removeDuplicates()

    let categoriaPub = publisher(for: \.categoriaSelecionada)
        .removeDuplicates()

    textoPub.combineLatest(categoriaPub)
        .map { texto, categoria in
            repositorio.buscar(texto: texto, categoria: categoria)
        }
        .receive(on: RunLoop.main)
        .assign(to: \.resultados, on: self)
        .store(in: &cancellables)
}

// Cadeia de operadores:
// textoBusca  ──debounce(300ms)──removeDuplicates──┐
//                                                   combineLatest──map──assign
// categoriaSelecionada──removeDuplicates────────────┘

