m15-design-system/design-tokens-and-comp.solution:
// Tokens de cor (semânticos):
extension Color {
    static let tokenAcaoPrimaria = Color(red: 0.2, green: 0.47, blue: 0.96)
    static let tokenTextoBotao   = Color.white
}

// Tokens de tipografia:
extension Font {
    static let tokenBotao = Font.system(size: 16, weight: .semibold)
}

// Tokens de espaçamento:
enum Espacamento {
    static let sm: CGFloat = 8
    static let md: CGFloat = 16
    static let lg: CGFloat = 24
}

// Token de forma:
enum Raio {
    static let botao: CGFloat = 10
}

// Componente refatorado:
struct BotaoPrimario: View {
    let titulo: String
    var body: some View {
        Text(titulo)
            .font(.tokenBotao)
            .foregroundStyle(Color.tokenTextoBotao)
            .padding(.horizontal, Espacamento.lg)
            .padding(.vertical, Espacamento.sm + 4)  // 12pt
            .background(Color.tokenAcaoPrimaria)
            .clipShape(RoundedRectangle(cornerRadius: Raio.botao))
    }
}

// Vantagem: mudar a cor primária do app = 1 linha, não 50.

m15-design-system/hig-principles.prompt:
Este ícone de fechar tem apenas 16x16 pontos visualmente, mas precisa de área de toque adequada. Corrija:

Button {
    fechar()
} label: {
    Image(systemName: "xmark")
        .font(.system(size: 12))
}

m15-design-system/hig-principles.solution:
Button {
    fechar()
} label: {
    Image(systemName: "xmark")
        .font(.system(size: 12))  // tamanho visual mantido
        .frame(width: 44, height: 44)  // área de toque mínima das HIG
        .contentShape(Rectangle())  // garante que toda a área é tocável
}

Alternativa com padding:
Image(systemName: "xmark")
    .font(.system(size: 12))
    .padding(16)  // 12 + 16*2 = 44 de área total

Motivo: dedos têm área de contato de ~44pts. Alvos menores causam erros de toque frequentes — o usuário toca na área errada.

